INSERT INTO `evaluations` VALUES (4,32,90,NULL,NULL,NULL,'[{\"point\":\"질문에 대한 직접적인 시도\",\"detail\":\"모든 질문에 대해 답변을 시도했으며, AI 사용 경험과 이점에 대해 간략하게 언급했습니다.\",\"quote\":\"yes, I used to AI applications in my daily life.\"},{\"point\":\"핵심 이점 언급\",\"detail\":\"AI의 중요한 이점 중 하나로 \'시간 절약\'을 반복적으로 언급했습니다.\",\"quote\":\"I don\'t waste time using AI tools.\"}]','[{\"point\":\"문법 오류 수정\",\"detail\":\"AI 사용 경험을 설명하는 문장에서 시제와 명사의 복수형 사용에 오류가 있습니다.\",\"studentSaid\":\"I used to AI applications in my daily life. so I can get many information anytime anywhere.\",\"betterWay\":\"I use AI applications in my daily life. For example, my smartphone\'s voice assistant helps me get a lot of information anytime, anywhere.\"},{\"point\":\"어휘 및 표현의 다양성 부족\",\"detail\":\"특정 표현(\'don\'t waste time\')이 반복되며, \'checking do many searching data\'와 같이 어색한 표현이 사용되었습니다.\",\"studentSaid\":\"I don\'t have to checking do many searching data. so I don\'t waste my time.\",\"betterWay\":\"I don\'t have to check or search through a lot of data manually, which saves me a lot of time.\"},{\"point\":\"답변의 구체성 및 확장 부족\",\"detail\":\"AI가 사용되는 제품/서비스에 대한 구체적인 예시 없이 막연하게 언급했습니다.\",\"studentSaid\":\"I used to AI applications in my daily life.\",\"betterWay\":\"My smartphone uses AI for voice assistants like Siri, which helps me set reminders or find information quickly.\"}]',NULL,NULL,'2026-03-27 16:20:26'),(5,33,NULL,NULL,NULL,NULL,'[]','[{\"point\":\"점수 미달\",\"detail\":\"답변이 전혀 없어 평가할 수 있는 내용이 없습니다. 질문에 대한 최소한의 응답이라도 시도해야 합니다.\",\"studentSaid\":\"\",\"betterWay\":\"Well, I haven\'t really used any AI tools in my daily life yet, but I\'m curious about them.\"},{\"point\":\"질문 이해 및 구성 부족\",\"detail\":\"질문을 이해하고 그에 맞춰 답변을 구성하는 연습이 필요합니다. 침묵은 점수에 가장 치명적입니다.\",\"studentSaid\":\"\",\"betterWay\":\"I think AI tools can help people by automating repetitive tasks, like scheduling appointments or managing emails.\"},{\"point\":\"의견 제시 미흡\",\"detail\":\"복잡한 질문이라도 자신의 의견을 명확히 제시하고 간단한 이유를 덧붙이는 연습이 중요합니다. 침묵은 어떤 의견도 전달하지 못합니다.\",\"studentSaid\":\"\",\"betterWay\":\"I believe AI will create new job opportunities, especially in areas like AI development and maintenance, though some jobs might be lost.\"}]',NULL,NULL,'2026-03-27 16:20:54'),(6,34,50,NULL,NULL,NULL,'[{\"point\":\"질문에 대한 시도\",\"detail\":\"비록 불완전하지만, 학생은 모든 질문에 대해 답변을 시도했습니다.\",\"quote\":\"yes, I used to AI applications in my daily life.\"}]','[{\"point\":\"문법적 정확성 부족\",\"detail\":\"과거 습관을 나타내는 \'used to\'를 현재 사용을 설명하는 데 잘못 사용했습니다.\",\"studentSaid\":\"I used to AI applications in my daily life.\",\"betterWay\":\"I use AI applications in my daily life.\"},{\"point\":\"질문에 대한 구체성 및 완전성 부족\",\"detail\":\"Q1에서 AI 도구의 구체적인 \'예시\'를 묻는 부분과 Q2에서 \'얼마나 자주\' 사용하는지, \'어떤 방식\'으로 도움이 되는지 명확히 설명하지 못했습니다.\",\"studentSaid\":\"so I can get many information anytime anywhere.\",\"betterWay\":\"For instance, I use virtual assistants like Siri to set alarms and check the weather. They help me save time by quickly providing information.\"},{\"point\":\"핵심적인 답변 누락\",\"detail\":\"세 번째 질문에 대한 답변으로 질문 내용을 그대로 반복했습니다. 이는 답변을 하지 않은 것으로 간주됩니다.\",\"studentSaid\":\"Some people believe AI will significantly improve our quality of life in the future, while others are concerned about its potential risks. What is your overall opinion on the future impact of AI, and why?\",\"betterWay\":\"I believe the most significant positive impact of AI will be in personalized healthcare, where it can provide early diagnoses and tailored treatments. However, job displacement in certain sectors could be a major negative impact.\"}]',NULL,NULL,'2026-03-27 16:22:58'),(7,35,45,NULL,NULL,NULL,'[{\"point\":\"일부 질문에 대한 긍정적 답변 시도\",\"detail\":\"첫 번째 질문에 \'yes\'로 시작하며 답변을 시도했습니다.\",\"quote\":\"yes, I used to AI applications in my daily life.\"},{\"point\":\"아이디어 제시\",\"detail\":\"두 번째 질문에서 AI의 이점으로 \'시간 절약\'이라는 핵심 아이디어를 제시했습니다.\",\"quote\":\"because I don\'t waste time using AI tools.\"}]','[{\"point\":\"문법 오류 및 시제 불일치\",\"detail\":\"현재 사용 여부를 묻는 질문에 과거 시제(used to)를 사용하여 의미 전달이 부정확합니다. 또한 \'many information\'은 부적절한 표현입니다.\",\"studentSaid\":\"yes, I used to AI applications in my daily life. so I can get many information anytime anywhere.\",\"betterWay\":\"Yes, I use AI-powered applications in my daily life. For example, I use a translation app to get much information easily anytime, anywhere.\"},{\"point\":\"질문 반복 및 문장 구성\",\"detail\":\"두 번째 질문에서 \'yes\'로 시작하는 것이 부자연스러우며, 문장이 길게 이어져 부자연스럽습니다. \'with daily work\'와 같은 전치사 사용도 어색합니다.\",\"studentSaid\":\"yes, using AI tools with daily work is the biggest benefit. because I don\'t waste time using AI tools.\",\"betterWay\":\"In my opinion, the biggest advantage of integrating AI is increased efficiency. This is because AI tools help me save a lot of time on daily tasks.\"},{\"point\":\"질문에 대한 미응답 (질문 반복)\",\"detail\":\"세 번째 질문에 대한 답변 없이 질문 내용을 그대로 반복하여 답변으로 인정할 수 없습니다. 이는 시험에서 치명적인 실수입니다.\",\"studentSaid\":\"Some people believe AI will significantly improve our quality of life in the future, while others are concerned about its potential risks. What is your overall opinion on the future impact of AI, and why?\",\"betterWay\":\"(해당 질문에 대한 직접적인 답변을 제시해야 합니다.)\"}]',NULL,NULL,'2026-03-27 16:49:51'),(8,36,110,NULL,NULL,NULL,'[{\"point\":\"질문에 대한 직접적인 응답\",\"detail\":\"주어진 질문에 대해 \'동의한다\'는 의견을 명확하게 밝히며 시작했습니다.\",\"quote\":\"yes, i agree experimenting with a four-day work week.\"},{\"point\":\"주장의 근거 제시 시도\",\"detail\":\"개인적인 경험과 과거와의 비교를 통해 자신의 의견을 뒷받침하려는 노력이 보입니다.\",\"quote\":\"for example, when i was a employee. i was tired every day, so i wasn\'t able to focus on my work.\"},{\"point\":\"기본적인 연결어 사용\",\"detail\":\"\'for example\', \'but\', \'also\' 등 기본적인 연결어를 사용하여 생각의 흐름을 만들었습니다.\",\"quote\":\"for example\",\"quote_2\":\"but\",\"quote_3\":\"also\"}]','[{\"point\":\"문법 정확성 (관사, 복수형)\",\"detail\":\"부정관사와 명사의 복수형 사용이 부정확했습니다. \'employee\'는 단수 명사이므로 \'an employee\' 또는 복수형 \'employees\'가 되어야 합니다.\",\"studentSaid\":\"when i was a employee. most of all experimenting with a five-day work week is making employee so tired.\",\"betterWay\":\"when I was an employee. Most of all, a five-day work week makes employees so tired.\"},{\"point\":\"어색한 표현 및 동사 선택\",\"detail\":\"\'experimenting with\'라는 표현을 잘못된 맥락에서 반복적으로 사용했습니다. 자신의 경험을 설명할 때는 \'worked\'나 \'tried\'와 같은 동사가 더 적절합니다. 또한, \'focus my work\' 대신 \'focus on my work\'와 같이 올바른 전치사를 사용해야 합니다.\",\"studentSaid\":\"yes, i agree experimenting with a four-day work week. but, when i was experimenting with a four-day work week, i was able to focus my work.\",\"betterWay\":\"Yes, I agree *with* a four-day work week. But, when I *worked* a four-day work week, I was able to focus *on* my work.\"},{\"point\":\"문장 구조 및 의미 명확성\",\"detail\":\"마지막 문장의 문법적 오류가 많아 의도하는 바가 명확하게 전달되지 않았습니다. 비교급 표현과 시제, 그리고 주어-동사 일치에 더 신경 써야 합니다.\",\"studentSaid\":\"but it\'s make it same performances when they worked fie days.\",\"betterWay\":\"However, it didn\'t lead to better performance compared to working five days.\"}]',NULL,NULL,'2026-03-27 17:17:04'),(9,38,90,'학생의 답변은 질문에 대한 선호도를 명확히 밝히지 못했으며, 문법 오류와 어색한 표현이 많아 내용 전달이 어렵습니다. 전반적인 이해도가 부족하고 문장 구성 능력이 미흡합니다.','목표 점수 140점(Level 5-6)을 달성하기 위해서는 질문에 직접적으로 답변하고, 1-2가지 이유를 명확하고 간결한 문장으로 설명할 수 있어야 합니다. 현재 답변은 문법 오류가 너무 많고, 전달하려는 내용이 명확하지 않아 목표 레벨에 한참 미치지 못합니다.','[\"질문에서 요구하는 선호도(4일 근무 또는 5일 근무)를 첫 문장에서 명확히 밝히세요.\",\"각 문장의 주어와 동사를 정확하게 사용하여 기본적인 문법 오류를 줄이는 데 집중하세요.\",\"이유를 설명할 때는 \'First,\' \'Second,\' \'Because\'와 같은 간단한 연결어를 사용하여 논리적인 흐름을 만드세요.\",\"자신이 전달하고자 하는 내용을 쉬운 단어와 간결한 문장으로 표현하는 연습을 꾸준히 하세요.\"]','[{\"point\":\"질문에 대한 시도\",\"detail\":\"제한된 영어 실력에도 불구하고 질문의 주제에 대해 답변을 시도했습니다.\",\"quote\":\"yes, i agree experimenting with a four-day work week.\"},{\"point\":\"개인적인 경험 언급\",\"detail\":\"자신의 경험을 예시로 들어 설명을 구체화하려는 노력이 엿보입니다.\",\"quote\":\"for example, when i was a employee. i was tired every day\"}]','[{\"point\":\"질문에 대한 명확한 답변 부족\",\"detail\":\"어떤 근무 형태(4일 근무 또는 5일 근무)를 선호하는지 명확히 밝히지 않았습니다. \'agree experimenting with\'는 선호도 표현에 적합하지 않습니다.\",\"studentSaid\":\"yes, i agree experimenting with a four-day work week.\",\"betterWay\":\"I would prefer working four longer days per week.\"},{\"point\":\"전반적인 문법 오류\",\"detail\":\"시제, 주어-동사 일치, 관사, 전치사 등 문법 오류가 너무 많아 의미 파악이 어렵습니다.\",\"studentSaid\":\"experimenting with a five-day work week is making employee so tired. for example, when i was a employee. i was tired every day, so i wasn\'t able to focus on my work. but, when i was experimenting with a four-day work week, i was able to focus my work.\",\"betterWay\":\"Working a five-day week often makes employees very tired. For example, when I was an employee, I felt tired every day and struggled to focus on my work. However, when I worked a four-day week, I was able to focus better.\"},{\"point\":\"어휘 선택 및 표현의 부자연스러움\",\"detail\":\"\'experimenting with\'의 반복적인 오용과 \'compaire to past\', \'senior like my fathers age\' 등 부자연스러운 표현이 많습니다.\",\"studentSaid\":\"also compaire to past, senior like my fathers age was experimenting with a six-day work week. but it\'s make it same performances when they worked fie days.\",\"betterWay\":\"Also, compared to the past, people my father\'s age used to work a six-day week. But even then, their performance was often the same as when working five days.\"}]','[{\"question\":\"Some companies are experimenting with a four-day work week. Would you prefer working four longer days or five standard days per week? Provide reasons for your preference.\",\"answer\":\"I would definitely prefer working four longer days per week. My main reason is that it would provide a better work-life balance. Having a three-day weekend would give me more time to relax, pursue hobbies, or spend quality time with my family without feeling rushed. This extended break would help me recharge and come back to work feeling more energized and focused. Additionally, I believe knowing I have a longer weekend approaching would actually boost my productivity during those four working days. I\'d be more motivated to complete my tasks efficiently, leading to higher overall output. It\'s about the quality of work and life, not just the quantity of days spent at the office.\",\"answerKo\":\"저는 주 4일 근무를 선호합니다. 주된 이유는 일과 삶의 균형이 더 좋아질 것이기 때문입니다. 3일 주말은 제가 서두르지 않고 휴식을 취하거나, 취미 생활을 하거나, 가족과 더 좋은 시간을 보낼 수 있는 더 많은 시간을 줄 것입니다. 이 길어진 휴식은 제가 재충전하고, 더 활기차고 집중된 상태로 업무에 복귀하는 데 도움이 될 것입니다. 또한, 길어진 주말이 다가오고 있다는 것을 알면 그 4일 동안의 근무 생산성이 실제로 향상될 것이라고 생각합니다. 업무를 효율적으로 완료하려는 동기가 더 커져 전반적인 성과가 높아질 것입니다. 이것은 단순히 사무실에서 보내는 날짜의 양이 아니라 일과 삶의 질에 관한 것입니다.\",\"responseTime\":60}]','[{\"expression\":\"provide a better work-life balance\",\"meaning\":\"더 나은 일과 삶의 균형을 제공하다\",\"example\":\"A four-day work week can provide a better work-life balance for employees.\"},{\"expression\":\"pursue hobbies\",\"meaning\":\"취미 생활을 하다\",\"example\":\"Having more free time allows me to pursue hobbies like painting and hiking.\"},{\"expression\":\"recharge and come back to work feeling energized\",\"meaning\":\"재충전하고 활기찬 상태로 업무에 복귀하다\",\"example\":\"A long weekend helps me recharge and come back to work feeling energized.\"},{\"expression\":\"boost productivity\",\"meaning\":\"생산성을 높이다\",\"example\":\"Knowing I have a deadline often helps boost my productivity.\"},{\"expression\":\"complete tasks efficiently\",\"meaning\":\"업무를 효율적으로 완료하다\",\"example\":\"Good time management skills help me complete tasks efficiently.\"}]','2026-03-27 17:22:19'),(10,38,85,'학생은 4일 근무 주에 대한 선호를 나타내고 몇 가지 이유를 제시하려 했으나, 문법 오류가 많고 어휘 선택이 부정확하여 전반적인 의미 전달이 명확하지 않습니다.','목표 점수 140점(레벨 5-6)을 달성하려면 더 정확한 문법 구조와 적절한 어휘를 사용하여 명확하게 의사를 표현해야 합니다. 현재 답변은 문장 구조와 시제 사용이 불안정하며, 질문에 대한 직접적인 선호 표현도 다소 모호합니다.','[\"질문에 대한 직접적인 답변으로 시작하고, 선호도를 명확히 밝히세요.\",\"간단한 문장으로 명확한 이유를 1-2가지 제시하고, 기본적인 접속사(e.g., \'because\', \'also\')를 활용하세요.\",\"기본적인 문법(시제, 수일치, 관사 등) 오류를 줄이고 정확한 어휘를 사용하는 연습을 하세요.\"]','[{\"point\":\"질문에 대한 선호 언급\",\"detail\":\"4일 근무 주에 대한 선호를 언급하며 질문에 반응하려는 시도가 있었습니다.\",\"quote\":\"yes, i agree experimenting with a four-day work week.\"},{\"point\":\"경험 기반 이유 제시 시도\",\"detail\":\"개인적인 경험(피로도, 집중력)을 바탕으로 이유를 제시하려 했습니다.\",\"quote\":\"when i was a employee. i was tired every day, so i wasn\'t able to focus on my work. but, when i was experimenting with a four-day work week, i was able to focus my work.\"}]','[{\"point\":\"질문 이해 및 직접적 답변\",\"detail\":\"질문은 \'4일 근무 또는 5일 근무 중 무엇을 선호하는지\'를 묻는 것이므로, \'실험에 동의한다\'는 표현보다는 개인적인 선호를 명확히 밝히는 것이 중요합니다.\",\"studentSaid\":\"yes, i agree experimenting with a four-day work week.\",\"betterWay\":\"I would prefer working four longer days per week.\"},{\"point\":\"문법 및 어휘 정확성\",\"detail\":\"\'experimenting\' 대신 \'working\'을 사용하고, 관사(\'a employee\' -> \'an employee\'), 형용사(\'so tired\' -> \'very tired\'), 전치사(\'focus my work\' -> \'focus on my work\') 등의 오류를 수정해야 합니다. 또한 시제와 주어-동사 일치에도 주의해야 합니다.\",\"studentSaid\":\"most of all experimenting with a five-day work week is making employee so tired. for example, when i was a employee. i was tired every day, so i wasn\'t able to focus on my work. but, when i was experimenting with a four-day work week, i was able to focus my work.\",\"betterWay\":\"Most of all, working a five-day week makes employees very tired. For example, when I was an employee, I felt tired every day and wasn\'t able to focus on my work. However, when I worked a four-day week, I was able to focus on my work.\"},{\"point\":\"문장 연결 및 논리\",\"detail\":\"\'compaire\' 철자 오류, \'my fathers age\'와 \'it\'s make it same performances\' 등 문장 구조가 매우 복잡하고 의미 파악이 어렵습니다. 불필요하거나 모호한 비교보다는 자신의 선호를 뒷받침하는 명확하고 간결한 이유를 제시하는 것이 좋습니다.\",\"studentSaid\":\"also compaire to past, senior like my fathers age was experimenting with a six-day work week. but it\'s make it same performances when they worked fie days.\",\"betterWay\":\"Also, a longer weekend allows for better rest and personal time, which can lead to increased productivity during working hours.\"}]','[{\"question\":\"TOEIC Speaking Part 5\\nSome companies are experimenting with a four-day work week. Would you prefer working four longer days or five standard days per week? Provide reasons for your preference.\",\"answer\":\"I would definitely prefer working four longer days per week. My main reason is that it provides a longer weekend, which allows for better rest and personal time. With three days off, I could fully recharge, pursue hobbies, or spend more time with family. This improved work-life balance would make me more focused and productive during my four working days. Also, it could reduce commuting time and costs since I\'d only travel to work four times instead of five.\",\"answerKo\":\"저는 확실히 주 4일 근무를 선호할 것입니다. 가장 큰 이유는 더 긴 주말을 가질 수 있어 충분한 휴식과 개인적인 시간을 가질 수 있기 때문입니다. 3일의 휴무가 있다면 완전히 재충전하고, 취미 생활을 하거나 가족과 더 많은 시간을 보낼 수 있습니다. 이렇게 개선된 일과 삶의 균형은 제가 4일 근무하는 동안 더 집중하고 생산성을 높일 수 있게 해줄 것입니다. 또한, 일주일에 다섯 번이 아닌 네 번만 출근하기 때문에 통근 시간과 비용도 줄일 수 있습니다.\",\"responseTime\":60}]','[{\"expression\":\"I would definitely prefer working [X] days per week.\",\"meaning\":\"저는 분명히 주 [X]일 근무를 선호합니다.\",\"example\":\"I would definitely prefer working four days per week.\"},{\"expression\":\"provides a longer weekend\",\"meaning\":\"더 긴 주말을 제공합니다\",\"example\":\"A four-day work week provides a longer weekend.\"},{\"expression\":\"allows for better rest and personal time\",\"meaning\":\"더 나은 휴식과 개인적인 시간을 가질 수 있게 합니다\",\"example\":\"A longer weekend allows for better rest and personal time.\"},{\"expression\":\"improved work-life balance\",\"meaning\":\"개선된 일과 삶의 균형\",\"example\":\"This improved work-life balance would make me more productive.\"},{\"expression\":\"more focused and productive\",\"meaning\":\"더 집중하고 생산적인\",\"example\":\"I would be more focused and productive during my working days.\"}]','2026-03-27 17:22:34'),(11,39,NULL,'학생이 어떠한 답변도 제공하지 않았으므로, 채점할 내용이 없어 0점으로 평가됩니다.','목표 점수 140점(레벨 5-6)을 달성하기 위해서는 모든 질문에 대해 최소한의 답변이라도 해야 합니다. 현재는 어떠한 답변도 제공되지 않아 영어 구사 능력, 어휘력, 문법, 발음 등을 전혀 평가할 수 없습니다. 질문의 요지를 파악하고 제한 시간 내에 최소 1~2문장으로라도 의견을 표현하는 연습이 시급합니다.','[\"모든 질문에 대해 짧고 간단하게라도 답변하는 연습을 시작하세요. 침묵은 점수에 매우 부정적인 영향을 미칩니다.\",\"각 질문의 핵심 키워드를 파악하고, 그에 대한 간단한 찬성/반대 의견이나 개인적인 경험을 한두 문장으로 정리하여 말하는 연습을 하세요.\",\"제한 시간 안에 답변을 마칠 수 있도록 타이머를 설정하고 말하기 연습을 하는 것이 중요합니다. 목표 점수대에서는 유창성이 점수에 큰 영향을 미칩니다.\",\"기본적인 연결어(First, Also, Because 등)를 사용하여 답변의 흐름을 만들고, 문장을 논리적으로 연결하는 연습을 통해 답변의 구조를 개선할 수 있습니다.\"]','[]','[]','[{\"question\":\"Q1: Have you ever used any AI-powered tools or features in your daily life, such as voice assistants, smart home devices, or recommendation systems? If so, what was your experience like?\",\"answer\":\"Yes, I often use voice assistants like Siri to set alarms and check the weather. It\'s very convenient because I can get information quickly without using my hands.\",\"answerKo\":\"네, 저는 시리 같은 음성 비서를 자주 사용해서 알람을 설정하고 날씨를 확인합니다. 손을 사용하지 않고도 빠르게 정보를 얻을 수 있어서 매우 편리합니다.\",\"responseTime\":15},{\"question\":\"Q2: Do you believe AI technology makes our daily lives more convenient or more complicated in general? Why do you think so?\",\"answer\":\"I believe AI generally makes our lives more convenient. For example, navigation apps with AI help us find the best routes, saving time and reducing stress.\",\"answerKo\":\"저는 AI가 일반적으로 우리의 삶을 더 편리하게 만든다고 생각합니다. 예를 들어, AI 기반 내비게이션 앱은 최적의 경로를 찾는 데 도움을 주어 시간과 스트레스를 줄여줍니다.\",\"responseTime\":15},{\"question\":\"Q3: What are some potential benefits and drawbacks of integrating AI tools further into both our homes and workplaces? Provide specific examples to support your answer.\",\"answer\":\"In homes, a big benefit is increased efficiency; smart thermostats can learn preferences and save energy. However, a drawback is privacy concerns, as these devices collect personal data. In workplaces, AI can automate repetitive tasks, boosting productivity, but it could also lead to job displacement for some roles.\",\"answerKo\":\"가정에서 큰 이점은 효율성 증가입니다. 스마트 온도 조절기는 사용자의 선호도를 학습하여 에너지를 절약할 수 있습니다. 하지만 단점은 이러한 기기들이 개인 데이터를 수집하기 때문에 프라이버시 문제가 발생할 수 있다는 점입니다. 직장에서는 AI가 반복적인 업무를 자동화하여 생산성을 높일 수 있지만, 일부 직무에서는 일자리 감소로 이어질 수도 있습니다.\",\"responseTime\":30}]','[{\"expression\":\"voice assistants\",\"meaning\":\"음성 비서\",\"example\":\"I use voice assistants to play music and set reminders.\"},{\"expression\":\"get information quickly\",\"meaning\":\"빠르게 정보를 얻다\",\"example\":\"With a quick search, you can get information quickly on almost any topic.\"},{\"expression\":\"generally makes our lives more convenient\",\"meaning\":\"일반적으로 우리의 삶을 더 편리하게 만든다\",\"example\":\"Online shopping generally makes our lives more convenient.\"},{\"expression\":\"boosting productivity\",\"meaning\":\"생산성을 높이다\",\"example\":\"New software can significantly contribute to boosting productivity in the office.\"},{\"expression\":\"job displacement\",\"meaning\":\"일자리 감소/대체\",\"example\":\"Automation can lead to job displacement in some industries.\"}]','2026-03-27 17:46:57');
