DROP TABLE IF EXISTS `questions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `questions` (
  `question_id` int NOT NULL AUTO_INCREMENT,
  `part_number` tinyint NOT NULL COMMENT 'Part 1~5',
  `question_type` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '지문 읽기, 사진 묘사, 질문 응답, 정보 활용, 의견 제시',
  `content_text` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '문제 지문',
  `image_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '사진 묘사용 이미지 경로',
  `audio_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '듣기 지문용 오디오 경로',
  `preparation_time` int NOT NULL COMMENT '준비 시간(초)',
  `response_time` int NOT NULL COMMENT '응답 시간(초)',
  `is_set` tinyint(1) NOT NULL DEFAULT '0' COMMENT '세트 문항 여부 (0=단독, 1=세트)',
  `set_order` tinyint DEFAULT NULL COMMENT '세트 내 출제 순서 (1,2,3...)',
  PRIMARY KEY (`question_id`)
