INSERT INTO `questions` VALUES (1066,1,'지문 읽기','{\"text\":\"Welcome to the annual technology conference. We are pleased to announce that this year\'s event will feature over fifty speakers from around the world. Sessions will cover topics ranging from artificial intelligence to sustainable energy solutions. Please check the schedule posted near the registration desk for room assignments and times.\",\"questionType\":\"지문 읽기\"}',NULL,NULL,45,45,0,NULL),(1067,2,'사진 묘사','{\"text\":\"Describe the picture below.\",\"hint\":\"A bright, modern co-working space with large windows letting in natural light. In the foreground, a woman wearing a blue blazer is typing on a laptop while talking on the phone. Behind her, two men in casual shirts are standing near a whiteboard, pointing at a chart and discussing. On the right side, a young man with headphones is sitting on a bean bag, reading something on a tablet. Several potted plants are placed around the room, and coffee cups are visible on the desks.\",\"questionType\":\"사진 묘사\"}','https://images.pexels.com/photos/3184292/pexels-photo-3184292.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,45,30,0,NULL),(1069,4,'정보 활용','{\"questionType\":\"정보 활용\",\"infoTitle\":\"Annual Marketing Workshop\",\"infoDetails\":\"Date: March 15\\nTime: 9:00 AM - 4:00 PM\\nLocation: Conference Room A, 3rd Floor\",\"infoSchedule\":[{\"time\":\"9:00 - 10:30\",\"content\":\"Lecture: Brand Strategy Overview\",\"speaker\":\"Sarah Kim\"},{\"time\":\"10:30 - 10:45\",\"content\":\"Break (Coffee & Refreshments)\",\"speaker\":\"-\"},{\"time\":\"10:45 - 12:00\",\"content\":\"Presentation: Social Media Trends\",\"speaker\":\"David Park\"},{\"time\":\"12:00 - 1:00\",\"content\":\"Lunch (included in registration)\",\"speaker\":\"-\"},{\"time\":\"1:00 - 2:30\",\"content\":\"Workshop: Customer Engagement\",\"speaker\":\"Emily Chen\"},{\"time\":\"2:30 - 4:00\",\"content\":\"Group Discussion: Final Project\",\"speaker\":\"-\"}],\"subQuestions\":[{\"text\":\"What time does the workshop begin and where is it being held?\",\"responseTime\":15},{\"text\":\"What topic is covered right after the coffee break?\",\"responseTime\":15},{\"text\":\"I heard the group project is in the morning. Is that correct?\",\"responseTime\":30}]}',NULL,NULL,45,30,1,1),(1070,5,'의견 제시','{\"text\":\"Some people believe that employees should be required to work in the office every day, while others think that remote work should be an option. Which do you prefer and why? Give specific reasons and examples to support your opinion.\",\"questionType\":\"의견 제시\"}',NULL,NULL,30,60,0,NULL),(1071,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"How often do you use public transportation?\",\"responseTime\":15},{\"text\":\"What do you think are the main advantages of using public transportation compared to driving?\",\"responseTime\":15},{\"text\":\"Some cities are investing heavily in improving public transportation systems. Do you think this is a good use of public funds? Why or why not?\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1072,5,'의견 제시','{\"text\": \"As Artificial Intelligence (AI) continues to evolve and integrate into various workplaces, there are different views on how employees should adapt. Some people argue that employees should primarily focus on developing unique \'human skills\' like creativity, critical thinking, and emotional intelligence, which AI cannot easily replicate. On the other hand, others believe that it\'s more beneficial for employees to learn how to effectively collaborate with AI tools, using them to enhance their productivity and problem-solving abilities. Which approach do you think is more beneficial for employees\' long-term career development in the evolving job market? Explain your preference with specific reasons and examples.\", \"questionType\": \"의견 제시\"}',NULL,NULL,30,60,0,NULL),(1073,5,'의견 제시','{\"text\": \"In today\'s rapidly evolving technological landscape, artificial intelligence (AI) is transforming various industries and raising questions about the future of employment. Some people are concerned about job displacement, while others see new opportunities emerging. In your opinion, what is the best way for individuals to prepare for a job market that will be increasingly influenced by AI?\", \"questionType\": \"의견 제시\"}',NULL,NULL,30,60,0,NULL),(1074,5,'의견 제시','{\"text\": \"The recent trend of implementing a 4-day work week has gained popularity in many companies. While it offers potential benefits like improved employee well-being and productivity, some businesses face challenges in maintaining operational efficiency or customer service during reduced workdays. What is the best way for companies to successfully implement a 4-day work week while ensuring that productivity and customer satisfaction are not negatively impacted? Provide specific reasons and examples to support your opinion. You will have 30 seconds to prepare your response and 60 seconds to speak.\", \"questionType\": \"의견 제시\"}',NULL,NULL,30,60,0,NULL),(1075,5,'의견 제시','{\"text\": \"Do you agree or disagree that companies should implement a four-day work week for all employees? Give specific reasons to support your opinion.\", \"questionType\": \"의견 제시\"}',NULL,NULL,30,60,0,NULL),(1076,3,'질문 응답','{\"questionType\": \"질문 응답\", \"subQuestions\": [{\"text\": \"Do you currently use any AI-powered tools or applications in your daily life? If so, could you give an example of how you use them?\", \"responseTime\": 15}, {\"text\": \"How do you think AI technology has changed the way people manage their daily responsibilities, either at home or at work?\", \"responseTime\": 15}, {\"text\": \"In your opinion, what are the most significant advantages and potential disadvantages of relying more on AI technology for everyday tasks? Please explain with specific reasons.\", \"responseTime\": 30}]}',NULL,NULL,3,15,1,1),(1077,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Have you ever used any AI-powered tools or applications in your daily life? If so, what was it?\",\"responseTime\":15},{\"text\":\"Do you believe that AI tools generally make daily tasks more efficient or more complicated? Why or why not?\",\"responseTime\":15},{\"text\":\"Many people predict that AI will significantly change various aspects of our lives in the coming years. How do you think AI will impact your personal and professional life in the future? Provide specific examples to support your opinion.\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1078,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Do you currently subscribe to any services, such as streaming platforms or fitness apps? If so, what types of services are they?\",\"responseTime\":15},{\"text\":\"In your opinion, what is the main benefit of subscribing to a service compared to making one-time purchases?\",\"responseTime\":15},{\"text\":\"With so many subscription options available today, what are some potential disadvantages of having multiple subscriptions, and what advice would you give someone to manage them effectively?\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1079,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Do you currently subscribe to any services, such as streaming platforms, food delivery, or software? Please tell me about them.\",\"responseTime\":15},{\"text\":\"In your opinion, what is the main benefit of subscribing to a service rather than making one-time purchases? And what is a potential drawback?\",\"responseTime\":15},{\"text\":\"With so many subscription options available today, what factors do you consider most important when deciding whether to subscribe to a new service? Please explain your reasoning.\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1080,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Do you often use any AI-powered applications or devices in your daily life? If so, please give an example of how you use them.\",\"responseTime\":15},{\"text\":\"In what ways do you think AI technology has changed how people perform routine tasks, such as shopping or communicating?\",\"responseTime\":15},{\"text\":\"As AI technology continues to advance, some people are concerned about its potential impact on employment and personal privacy. What is your opinion on these concerns, and how do you think society should address them?\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1081,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Do you currently use any AI-powered tools or applications in your daily routine? If so, can you provide an example of how you use them?\",\"responseTime\":15},{\"text\":\"How do you feel about the increasing presence of AI tools in various aspects of daily life, such as in customer service or content creation? Is this generally a positive or negative development?\",\"responseTime\":15},{\"text\":\"Some experts predict that AI will revolutionize the way we work, while others are concerned about job displacement. What is your opinion on the potential impact of AI on the future job market, and what steps do you think individuals or companies should take to prepare for these changes?\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1082,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Do you currently use any AI-powered tools or virtual assistants in your daily life? If so, what do you use them for?\",\"responseTime\":15},{\"text\":\"What do you think are the biggest advantages of using AI tools to help with everyday tasks?\",\"responseTime\":15},{\"text\":\"Some people believe that AI will significantly improve our quality of life, while others worry about its potential drawbacks. What is your opinion on the future impact of AI on daily life, and why do you think that way?\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1083,5,'의견 제시','{\"text\": \"Do you agree or disagree with implementing a 4-day work week for most industries? Give specific reasons for your opinion.\", \"questionType\": \"의견 제시\"}',NULL,NULL,30,60,0,NULL),(1084,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Have you used any AI tools or applications in your daily life recently? If so, what kind?\",\"responseTime\":15},{\"text\":\"Do you think AI tools make your daily tasks more efficient or easier to manage? Why or why not?\",\"responseTime\":15},{\"text\":\"Some people are excited about the future of AI, while others are concerned. What are your thoughts on the increasing presence of AI in our daily lives? Please provide specific reasons.\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1085,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Have you used any AI-powered tools or applications in your daily life? If so, could you give an example of how you use it?\",\"responseTime\":15},{\"text\":\"What do you think is the biggest benefit of using AI tools to help with daily tasks or work?\",\"responseTime\":15},{\"text\":\"Some people believe AI will significantly improve our quality of life in the future, while others are concerned about its potential risks. What is your overall opinion on the future impact of AI, and why?\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1086,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Have you used any AI-powered tools or applications in your daily life recently? If so, please give an example.\",\"responseTime\":15},{\"text\":\"In what specific ways do you think AI tools can help people manage their daily responsibilities more efficiently?\",\"responseTime\":15},{\"text\":\"There are growing discussions about the potential impact of AI on the job market and various industries. What is your opinion on whether AI will create more job opportunities or lead to significant job losses in the future? Please explain your reasoning.\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1087,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Have you noticed any AI tools being used in products or services you regularly use, such as smartphones or smart home devices? Please explain.\",\"responseTime\":15},{\"text\":\"In your opinion, what is one significant advantage that AI-powered tools offer in daily tasks?\",\"responseTime\":15},{\"text\":\"As AI technology continues to advance, do you believe its widespread use will mostly improve or complicate our daily lives? Please provide specific reasons for your view.\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1088,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Do you currently use any AI-powered tools or features in your daily life, such as virtual assistants or personalized recommendations? If so, what are some examples?\",\"responseTime\":15},{\"text\":\"How often do you rely on these AI tools, and in what ways do you find them most helpful for your daily routine?\",\"responseTime\":15},{\"text\":\"Looking ahead, what do you think will be the most significant positive or negative impact of AI on people\'s daily lives in the next five to ten years? Explain your reasoning.\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1089,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Have you ever used any AI tools, such as AI chatbots or voice assistants, for personal tasks in your daily life? Please tell me about your experience.\",\"responseTime\":15},{\"text\":\"Do you believe that AI tools will significantly change the way people work in the next few years? Why or why not?\",\"responseTime\":15},{\"text\":\"Some people are excited about the potential benefits of AI, while others are worried about its risks. What is your overall opinion on the growing use of AI in daily life, and what do you think are the most important things to consider as AI technology advances?\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1090,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Do you currently use any AI-powered tools or features in your daily routine? If so, please give an example.\",\"responseTime\":15},{\"text\":\"How has using AI tools changed the way you accomplish tasks or manage information? Explain your experience.\",\"responseTime\":15},{\"text\":\"As AI technology continues to develop, what do you think will be the biggest positive and negative impacts on people\'s daily lives in the next 5-10 years? Please provide specific reasons for your opinion.\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1091,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Have you used any AI-powered tools or features in your daily life, such as smart assistants or recommendation systems? If so, what was your experience like?\",\"responseTime\":15},{\"text\":\"Do you believe that AI technology significantly helps people save time or improve efficiency in their daily tasks, such as managing schedules or making purchases?\",\"responseTime\":15},{\"text\":\"What do you think are the biggest advantages and disadvantages of integrating AI more deeply into our everyday routines, and how should individuals or society prepare for these changes?\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1092,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Have you used any AI-powered tools or features in your daily life recently, such as smart assistants or personalized recommendations? If so, what kind?\",\"responseTime\":15},{\"text\":\"Do you think AI tools generally make your daily tasks easier or more complicated? Why?\",\"responseTime\":15},{\"text\":\"What are some potential benefits and drawbacks of increasingly relying on AI in various aspects of daily life, like education, work, or personal convenience? Explain your opinion.\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1093,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Do you currently use any AI-powered tools or applications in your daily life? If so, what are they?\",\"responseTime\":15},{\"text\":\"In what ways do you think AI tools could improve specific aspects of your daily routine in the future?\",\"responseTime\":15},{\"text\":\"While AI offers many conveniences, what are some potential concerns or challenges that might arise from its increased use in everyday life? Please explain.\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1094,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Do you currently use any AI-powered tools or applications in your daily life? If so, could you give an example of one you find useful?\",\"responseTime\":15},{\"text\":\"In your opinion, what is the biggest advantage of integrating AI technology into our everyday tasks and routines?\",\"responseTime\":15},{\"text\":\"Looking ahead, how do you foresee AI continuing to impact our personal and professional lives in the next five to ten years? Give specific reasons to support your view.\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1095,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Have you used any AI-powered tools or features in your daily life? If so, please give an example.\",\"responseTime\":15},{\"text\":\"What do you think are some benefits of using AI tools in daily tasks, such as for productivity or convenience?\",\"responseTime\":15},{\"text\":\"Do you believe AI technology will significantly change the way people work and interact in the next 10 years? Why or why not?\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1096,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Have you ever used any AI-powered tools or applications in your daily life, such as virtual assistants, chatbots, or recommendation systems? Please give an example if you have.\",\"responseTime\":15},{\"text\":\"Do you believe AI tools significantly improve your productivity or convenience in daily tasks? Why or why not?\",\"responseTime\":15},{\"text\":\"Some people are optimistic about the future of AI, while others are concerned about its potential downsides. What is your opinion on the increasing use of AI in daily life, and what are some of its potential benefits and drawbacks?\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1097,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Do you currently use any AI-powered tools or applications in your daily life? If so, could you give an example of how you use them?\",\"responseTime\":15},{\"text\":\"What do you think are the biggest advantages of using AI tools for personal tasks, and are there any potential disadvantages you\'ve noticed?\",\"responseTime\":15},{\"text\":\"Looking ahead, do you believe AI technology will mostly improve or complicate our daily lives in the next five to ten years? Please explain your reasoning with specific examples.\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1098,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Do you currently use any AI tools or applications in your daily life, such as virtual assistants or recommendation systems? If so, please give an example.\",\"responseTime\":15},{\"text\":\"In what ways do you think AI tools have made daily tasks more convenient or efficient for people?\",\"responseTime\":15},{\"text\":\"What are some of the potential challenges or concerns that society might face as AI tools become even more common in our daily lives? Please provide specific reasons to support your opinion.\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1099,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Do you think working from home has become more common recently? Why or why not?\",\"responseTime\":15},{\"text\":\"Do you believe AI tools can significantly improve workplace productivity? Why or why not?\",\"responseTime\":15},{\"text\":\"With the increasing integration of technology, especially AI, into the workplace, what do you think are the biggest challenges and benefits for employees?\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1100,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Have you ever used an AI tool or service in your daily life, such as a smart assistant or a recommendation system? If so, please tell me about your experience.\",\"responseTime\":15},{\"text\":\"Do you believe that AI tools generally make daily tasks more efficient, or do they sometimes create new challenges? Explain your perspective.\",\"responseTime\":15},{\"text\":\"Some people predict that AI will significantly change how we work and live in the next decade. What kind of positive and negative impacts do you expect AI to have on society, and why?\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1101,5,'의견 제시','{\"text\": \"Some companies are experimenting with a four-day work week. Do you agree or disagree that this should become a standard practice for all businesses? Give specific reasons to support your opinion.\", \"questionType\": \"의견 제시\"}',NULL,NULL,30,60,0,NULL),(1102,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Do you currently use any AI-powered tools or services in your daily life? If so, what are they?\",\"responseTime\":15},{\"text\":\"Have AI tools made any particular tasks significantly easier or more efficient for you? Please explain.\",\"responseTime\":15},{\"text\":\"What do you think are the potential benefits and drawbacks of using AI tools in various aspects of daily life? Provide specific examples to support your answer.\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1103,5,'의견 제시','{\"text\": \"Do you agree or disagree that companies should implement a four-day work week for their employees? Give specific reasons to support your opinion.\", \"questionType\": \"의견 제시\"}',NULL,NULL,30,60,0,NULL),(1104,5,'의견 제시','{\"text\": \"Some companies are experimenting with a four-day work week. Would you prefer working four longer days or five standard days per week? Provide reasons for your preference.\", \"questionType\": \"의견 제시\"}',NULL,NULL,30,60,0,NULL),(1105,3,'질문 응답','{\"questionType\":\"질문 응답\",\"subQuestions\":[{\"text\":\"Have you ever used any AI-powered tools or features in your daily life, such as voice assistants, smart home devices, or recommendation systems? If so, what was your experience like?\",\"responseTime\":15},{\"text\":\"Do you believe AI technology makes our daily lives more convenient or more complicated in general? Why do you think so?\",\"responseTime\":15},{\"text\":\"What are some potential benefits and drawbacks of integrating AI tools further into both our homes and workplaces? Provide specific examples to support your answer.\",\"responseTime\":30}]}',NULL,NULL,3,15,1,1),(1106,5,'의견 제시','{\"text\": \"Do you agree or disagree that companies should implement a 4-day work week for all employees? Give specific reasons to support your opinion.\", \"questionType\": \"의견 제시\"}',NULL,NULL,30,60,0,NULL),(1107,5,'의견 제시','{\"text\": \"Some people advocate for a four-day work week, while others prefer the traditional five-day structure. Which work week model do you believe is better for both employees and companies?\", \"questionType\": \"의견 제시\"}',NULL,NULL,30,60,0,NULL);
